// Some portions generated by Codex
package org.eclipse.rdf4j.benchmark.common;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Model;
import org.eclipse.rdf4j.model.util.Values;
import org.junit.jupiter.api.Test;

class ThemeQueryCatalogAdaptiveFilterPlacementTest {

	private static final String NAMESPACE = "http://example.com/theme/adaptive-filter/";

	@Test
	void adaptiveFilterPlacementThemeHasSkewedGateAndThirteenQueries() {
		Theme theme = Theme.valueOf("ADAPTIVE_FILTER_PLACEMENT");
		Model model = ThemeDataSetGenerator.generate(theme);
		IRI payload = Values.iri(NAMESPACE, "payload");
		IRI routedThrough = Values.iri(NAMESPACE, "routedThrough");
		IRI qualified = Values.iri(NAMESPACE, "qualified");

		long probes = model.filter(null, payload, null).size();
		long routedCandidates = model.filter(null, routedThrough, null).size();
		long qualifiedRoutes = model.filter(null, qualified, null).size();
		long qualifyingProbes = model.filter(null, routedThrough, null)
				.stream()
				.filter(statement -> model.contains((IRI) statement.getObject(), qualified, null))
				.count();

		assertTrue(probes >= 4_096, "The runtime policy needs enough prefixes to observe multiple windows");
		assertTrue(routedCandidates >= probes * 4,
				"The route join must expand each early filter candidate before qualification");
		assertTrue(qualifiedRoutes > probes,
				"Decoy routes must make the qualification predicate look more expensive than the probe scan");
		assertTrue(qualifyingProbes * 32 < probes,
				"The late qualification join must remove nearly all filter candidates");

		List<String> queries = ThemeQueryCatalog.queriesFor(theme);
		assertEquals(ThemeQueryCatalog.QUERY_COUNT, queries.size());
		assertTrue(queries.stream()
				.allMatch(query -> query.contains("adaptive-filter/routedThrough")
						&& query.contains("adaptive-filter/qualified")
						&& query.contains("FILTER(")));
	}
}
